c++面向对象程序设计1.函数(1)编写一个函数，计算直角坐标系中点 a(x0，y0)到点 b(x1，y1)的距离。
#include &lt;iostream&gt;
#include &lt;cmath&gt;

double calculateDistance(double x0, double y0, double x1, double y1) &#123;
    return sqrt((x1 - x0) * (x1 - x0) + (y1 - y0) * (y1 - y0));
&#125;

int main() &#123;
    double x0, y0, x1, y1;
    cin &gt;&gt; x0 &gt;&gt; y0 &gt;&gt; x1 &gt;&gt; y1;
    cout &lt;&lt; calculateDistance(x0, y0, x1, y1) &lt;&lt; endl;
    return 0;
&#125;



(2)求 a!+b!+c!的值，其中求n!要用一个函数实现，通过主函数输入a，b和c的值，并在主函数中输出计算的结果。
#include &lt;iostream&gt;

long long factorial(int n) &#123;
    if (n &#x3D;&#x3D; 0 || n &#x3D;&#x3D; 1) &#123;
        return 1;
    &#125;
    long long result &#x3D; 1;
    for (int i &#x3D; 2; i &lt;&#x3D; n; ++i) &#123;
        result *&#x3D; i;
    &#125;
    return result;
&#125;

int main() &#123;
    int a, b, c;
    cin &gt;&gt; a &gt;&gt; b &gt;&gt; c;
    cout &lt;&lt; factorial(a) + factorial(b) + factorial(c) &lt;&lt; endl;
    return 0;
&#125;

(3)编写一个函数。该函数读入一个整数，并判断这个整数是否为一个回文数字。例如4，44，434，4334，43534都是回文数字。
#include &lt;iostream&gt;

bool isPalindrome(int num) &#123;
    int original &#x3D; num, reversed &#x3D; 0, remainder;
    while (num !&#x3D; 0) &#123;
        remainder &#x3D; num % 10;
        reversed &#x3D; reversed * 10 + remainder;
        num &#x2F;&#x3D; 10;
    &#125;
    return original &#x3D;&#x3D; reversed;
&#125;

int main() &#123;
    int num;
    cin &gt;&gt; num;
    if (isPalindrome(num)) &#123;
        cout &lt;&lt; num &lt;&lt; &quot; 是回文数&quot; &lt;&lt; endl;
    &#125; else &#123;
        cout &lt;&lt; num &lt;&lt; &quot; 不是回文数&quot; &lt;&lt; endl;
    &#125;
    return 0;
&#125;




(4)编写一个程序，为选修3，4和5门课程的学生计算平均分，其中求平均分要用重载函数实现。
#include &lt;iostream&gt;

double average(int a, int b, int c) &#123;
    return (a + b + c) &#x2F; 3.0;
&#125;

double average(double a, double b, double c) &#123;
    return (a + b + c) &#x2F; 3.0;
&#125;

int main() &#123;
    int choice;
    cin &gt;&gt; choice;

    if (choice &#x3D;&#x3D; 1) &#123;
        int a, b, c;
        cin &gt;&gt; a &gt;&gt; b &gt;&gt; c;
        cout &lt;&lt; average(a, b, c) &lt;&lt; endl;
    &#125; else if (choice &#x3D;&#x3D; 2) &#123;
