    return (a * a + b * b &#x3D;&#x3D; c * c) || (a * a + c * c &#x3D;&#x3D; b * b) || (b * b + c * c &#x3D;&#x3D; a * a);
&#125;

double areaOfTriangle(double a, double b, double c) &#123;
    &#x2F;&#x2F; 使用海伦公式计算三角形面积
    double s &#x3D; (a + b + c) &#x2F; 2;  &#x2F;&#x2F; 半周长
    return sqrt(s * (s - a) * (s - b) * (s - c));  &#x2F;&#x2F; 面积
&#125;

int main() &#123;
