    if (isRightTriangle(a, b, c)) &#123;
        cout &lt;&lt; &quot;该三角形是直角三角形!&quot; &lt;&lt; endl;
        double area &#x3D; areaOfTriangle(a, b, c);
        cout &lt;&lt; &quot;直角三角形的面积为: &quot; &lt;&lt; area &lt;&lt; endl;
    &#125; else &#123;
        cout &lt;&lt; &quot;该三角形不是直角三角形!&quot; &lt;&lt; endl;
    &#125;

    return 0;
&#125;




